            const candidate = s.substring(i, j);

            // 2. Validate the structure of the candidate word
            let isWord = true;
            if (candidate.length === 0) {
                isWord = false;
            } else {
                // Check start/end characters
                if (candidate[0] === '-' || candidate[candidate.length - 1] === '-') {
                    isWord = false;
                } else {
                    // Check internal hyphens
                    for (let k = 1; k < candidate.length - 1; k++) {
                        if (candidate[k] === '-') {
                            // Hyphen must be surrounded by letters
                            if (!((candidate[k - 1] >= 'a' && candidate[k - 1] <= 'z') && 
                                  (candidate[k + 1] >= 'a' && candidate[k + 1] <= 'z'))) {
                                isWord = false;
                                break;
                            }
                        } else if (!(candidate[k] >= 'a' && candidate[k] <= 'z')) {
                            // Should not happen if isValidChar is correct
                            isWord = false;
                            break;
                        }
                    }
                }
            }

            if (isWord) {
                wordCounts.set(candidate, (wordCounts.get(candidate) || 0) + 1);
            }

            i = j; // Move past the maximal sequence
        } else {
            i++; // Move past separator
        }
    }


    // 3. Build the result array
    const ans = [];
    for (const query of queries) {
        // Since the problem statement guarantees queries[i] is a valid word, 
        // we just check the count in our map.
        ans.push(wordCounts.get(query) || 0);
    }

    return ans;
}

